// Case 0 compatibility mode:
// - Keep strict validation when position is provided
// - If position is missing, use DEFAULT_POSITION for SMIA calls without skill params

const DEFAULT_POSITION = 0; // set to null to enforce strict mode

const body = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};
const query = (msg.req && msg.req.query) ? msg.req.query : {};

let posRaw;
if (body.position !== undefined && body.position !== null && body.position !== "") {
  posRaw = body.position;
} else if (query.position !== undefined && query.position !== null && query.position !== "") {
  posRaw = query.position;
} else if (body.skillParams && body.skillParams.position !== undefined) {
  posRaw = body.skillParams.position;
}

let source = "request";
if ((posRaw === undefined || posRaw === null || posRaw === "") && DEFAULT_POSITION !== null) {
  posRaw = DEFAULT_POSITION;
  source = "default";
}

if (posRaw === undefined || posRaw === null || posRaw === "") {
  msg.statusCode = 400;
  msg.payload = { status: "error", reason: "Missing field: position" };
  return [null, msg];
}

const pos = Number(posRaw);
if (!Number.isInteger(pos) || pos < 0 || pos > 8) {
  msg.statusCode = 400;
  msg.payload = { status: "error", reason: "position must be integer 0..8" };
  return [null, msg];
}

msg.topic = "vicom/61/piso_0/lab/lego/commands";
msg.payload = `bandera_custom:${pos}`;

const httpMsg = {
  statusCode: 200,
  payload: {
    status: "ok",
    published: msg.topic,
    payload: msg.payload,
    position: pos,
    source
  }
};

return [msg, httpMsg];
